for qid, q, a, tags, diff, views, likes in mens_qs:
    questions.append(make_q(qid, "mens_health", q, a, tags, diff, views, likes))

print(f"현재까지 질문 수: {len(questions)}")
print("skin_hair:", sum(1 for q in questions if q['category']=='skin_hair'))
print("musculoskeletal:", sum(1 for q in questions if q['category']=='musculoskeletal'))
print("womens_health:", sum(1 for q in questions if q['category']=='womens_health'))
print("mens_health:", sum(1 for q in questions if q['category']=='mens_health'))

with open('qa_batch2.json', 'w', encoding='utf-8') as f:
    json.dump(questions, f, ensure_ascii=False, indent=2)

print("\n✅ 배치 2 저장 완료 (qa_batch2.json)")
